import{_ as s,o as n,c as e,a2 as i}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"用原型任务观察验证成功","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/validation/09-prototype-task-success-observations.md","filePath":"03-interaction-design/notes/validation/09-prototype-task-success-observations.md","lastUpdated":1784248569000}'),l={name:"03-interaction-design/notes/validation/09-prototype-task-success-observations.md"};function t(r,a,p,h,d,o){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="用原型任务观察验证成功" tabindex="-1">用原型任务观察验证成功 <a class="header-anchor" href="#用原型任务观察验证成功" aria-label="Permalink to &quot;用原型任务观察验证成功&quot;">​</a></h1><p>原型任务观察让参与者或检查者使用原型完成一个不泄露路径的现实任务，记录动作、判断、错误、反馈和结果。它验证原型范围内的流程、内容与状态假设；不能证明生产性能、后端正确、安全或完整可访问性。</p><h2 id="验证对象" tabindex="-1">验证对象 <a class="header-anchor" href="#验证对象" aria-label="Permalink to &quot;验证对象&quot;">​</a></h2><h3 id="任务成功" tabindex="-1">任务成功 <a class="header-anchor" href="#任务成功" aria-label="Permalink to &quot;任务成功&quot;">​</a></h3><p>参与者在没有非计划帮助的情况下达到预先定义的结果。结果应包含对象和业务状态，不能只以“点到最后一屏”为准。</p><h3 id="错误成功" tabindex="-1">错误成功 <a class="header-anchor" href="#错误成功" aria-label="Permalink to &quot;错误成功&quot;">​</a></h3><p>界面显示或参与者认为成功，但实际对象、金额、权限或状态错误。高风险任务必须单独记录，不应归入成功。</p><h3 id="部分成功" tabindex="-1">部分成功 <a class="header-anchor" href="#部分成功" aria-label="Permalink to &quot;部分成功&quot;">​</a></h3><p>任务的一部分完成，例如批量邀请 3 个成功、2 个失败。是否符合任务目标应在观察前定义。</p><h3 id="放弃与结果未知" tabindex="-1">放弃与结果未知 <a class="header-anchor" href="#放弃与结果未知" aria-label="Permalink to &quot;放弃与结果未知&quot;">​</a></h3><p>参与者明确停止，或原型无法判断最终状态。不要事后把无法完成解释为“只是不熟悉”。</p><h2 id="原型能力边界" tabindex="-1">原型能力边界 <a class="header-anchor" href="#原型能力边界" aria-label="Permalink to &quot;原型能力边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原型类型</th><th>可以验证</th><th>不能充分验证</th></tr></thead><tbody><tr><td>纸面/静态</td><td>分类、内容顺序、入口概念</td><td>输入、键盘、焦点、等待和动态状态</td></tr><tr><td>设计工具连线</td><td>主流程、文案、简单分支</td><td>原生行为、真实内容、网络和语义</td></tr><tr><td>浏览器代码原型</td><td>输入、响应式、键盘和部分状态</td><td>未连接的后端、安全和生产性能</td></tr><tr><td>服务集成原型</td><td>端到端数据与失败</td><td>仍需生产容量、兼容和运营验证</td></tr></tbody></table><p>开始前把未实现能力明确告知观察者和记录者，避免把原型限制误记为产品问题，或把顺滑假数据误记为工程可行。</p><h2 id="任务观察流程" tabindex="-1">任务观察流程 <a class="header-anchor" href="#任务观察流程" aria-label="Permalink to &quot;任务观察流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;写假设与完成标准&quot;] --&gt; P[&quot;准备原型和固定数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; T[&quot;给出不泄露路径的任务&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; O[&quot;观察动作、判断与状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; R[&quot;按成功、错误和帮助编码&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; I[&quot;解释问题与原型限制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; V[&quot;迭代并用同任务复测&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="设计任务" tabindex="-1">设计任务 <a class="header-anchor" href="#设计任务" aria-label="Permalink to &quot;设计任务&quot;">​</a></h2><p>任务说明包含场景、目标、必要材料和完成状态，不包含按钮、菜单或页面名。</p><p>错误示例：“点击右上角邀请，输入邮箱后按发送。”</p><p>合格示例：“你需要让李晓参与 Roadmap 项目，并允许她编辑任务。她的邮箱是 <a href="mailto:li@example.com" target="_blank" rel="noreferrer">li@example.com</a>。请完成邀请并确认结果。”</p><h3 id="任务数据" tabindex="-1">任务数据 <a class="header-anchor" href="#任务数据" aria-label="Permalink to &quot;任务数据&quot;">​</a></h3><p>使用真实长度、错误和对象状态：</p><ul><li>有效、重复和无效输入；</li><li>不同权限和对象版本；</li><li>长名称、空值和大量数据；</li><li>慢请求、失败和部分成功。</li></ul><p>原型状态必须可重复触发。随机错误会让不同观察无法比较。</p><h2 id="成功标准" tabindex="-1">成功标准 <a class="header-anchor" href="#成功标准" aria-label="Permalink to &quot;成功标准&quot;">​</a></h2><p>在观察前定义：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>成功：li@example.com 获得一个“编辑者”邀请；界面显示待接受；刷新或结果页可确认。</span></span>
<span class="line"><span>错误成功：邀请了错误邮箱或错误角色，但参与者认为完成。</span></span>
<span class="line"><span>部分成功：邀请创建，但角色或结果不可确认。</span></span>
<span class="line"><span>失败：未创建邀请或无法继续。</span></span>
<span class="line"><span>帮助：主持人提供任何超出任务材料的信息。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>原型若无法刷新，应使用内部状态面板或固定结果检查，不要假装已验证持久化。</p><h2 id="观察什么" tabindex="-1">观察什么 <a class="header-anchor" href="#观察什么" aria-label="Permalink to &quot;观察什么&quot;">​</a></h2><h3 id="行为" tabindex="-1">行为 <a class="header-anchor" href="#行为" aria-label="Permalink to &quot;行为&quot;">​</a></h3><p>入口选择、返回、重复点击、滚动、搜索、错误修正、取消和绕过。</p><h3 id="判断" tabindex="-1">判断 <a class="header-anchor" href="#判断" aria-label="Permalink to &quot;判断&quot;">​</a></h3><p>参与者在关键决策处的预测和理由。可以要求在不打断任务的情况下说明当前理解，但持续“出声思考”可能改变行为，要在报告中说明方法。</p><h3 id="系统状态" tabindex="-1">系统状态 <a class="header-anchor" href="#系统状态" aria-label="Permalink to &quot;系统状态&quot;">​</a></h3><p>原型展示的加载、结果、错误、焦点和数据变化。记录原型未实现与故障，不把它们混入产品结论。</p><h3 id="帮助" tabindex="-1">帮助 <a class="header-anchor" href="#帮助" aria-label="Permalink to &quot;帮助&quot;">​</a></h3><p>记录帮助发生在哪一步、具体提示和任务是否继续。主持人应避免指导性语气和赞同答案。</p><h3 id="可观察指标" tabindex="-1">可观察指标 <a class="header-anchor" href="#可观察指标" aria-label="Permalink to &quot;可观察指标&quot;">​</a></h3><ul><li>成功类别；</li><li>首次正确动作；</li><li>严重错误与恢复；</li><li>非计划帮助；</li><li>完成时间，仅在任务起止和原型速度可比时；</li><li>关键步骤犹豫或返回，需与行为证据一起解释。</li></ul><p>小样本不应产生精确总体百分比。结果用于发现机制和比较固定任务，不宣称代表总体。</p><h2 id="不依赖访谈的个人验证" tabindex="-1">不依赖访谈的个人验证 <a class="header-anchor" href="#不依赖访谈的个人验证" aria-label="Permalink to &quot;不依赖访谈的个人验证&quot;">​</a></h2><p>个人学习可以：</p><ul><li>让同伴只执行任务，不进行用户访谈；</li><li>使用认知走查模拟首次使用知识；</li><li>自己延迟一段时间后按脚本执行，并记录熟悉度偏差；</li><li>用公开问题构造失败数据和任务；</li><li>运行键盘、屏幕阅读器与故障检查。</li></ul><p>检查者已知道方案，证据强度低于独立参与者，报告必须说明。</p><h2 id="完整案例-验证批量邀请原型" tabindex="-1">完整案例：验证批量邀请原型 <a class="header-anchor" href="#完整案例-验证批量邀请原型" aria-label="Permalink to &quot;完整案例：验证批量邀请原型&quot;">​</a></h2><h3 id="假设与具体输入" tabindex="-1">假设与具体输入 <a class="header-anchor" href="#假设与具体输入" aria-label="Permalink to &quot;假设与具体输入&quot;">​</a></h3><p>假设：把多邮箱输入与逐项结果放在同一流程，可让项目管理员修正失败项而不重复成功邀请。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务：邀请 5 人为编辑者</span></span>
<span class="line"><span>输入：</span></span>
<span class="line"><span>li@example.com（有效）</span></span>
<span class="line"><span>wang@example.com（有效）</span></span>
<span class="line"><span>bad-address（格式错误）</span></span>
<span class="line"><span>member@example.com（已是成员）</span></span>
<span class="line"><span>timeout@example.com（服务超时）</span></span>
<span class="line"><span>完成：2 个新邀请、1 个已有成员不重复、格式错误被修正、超时项可重试</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>原型为可运行浏览器页面，具有固定 800 ms 等待和预设服务结果；未连接真实邮件与权限系统。</p><h3 id="任务说明" tabindex="-1">任务说明 <a class="header-anchor" href="#任务说明" aria-label="Permalink to &quot;任务说明&quot;">​</a></h3><p>“Roadmap 项目需要邀请给定的 5 个地址，并让他们能够编辑任务。请处理所有地址，并确认哪些已经生效、哪些还需要操作。”</p><h3 id="逐步观察记录" tabindex="-1">逐步观察记录 <a class="header-anchor" href="#逐步观察记录" aria-label="Permalink to &quot;逐步观察记录&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>行为</th><th>原型状态</th><th>观察编码</th></tr></thead><tbody><tr><td>1</td><td>粘贴 5 行</td><td>拆为 5 个标签</td><td>首次动作正确</td></tr><tr><td>2</td><td>选择编辑者并提交</td><td>格式错误即时出现</td><td>错误发现</td></tr><tr><td>3</td><td>修正为 <a href="mailto:bad@example.com" target="_blank" rel="noreferrer">bad@example.com</a></td><td>错误消失</td><td>自主恢复</td></tr><tr><td>4</td><td>再次提交</td><td>等待 800 ms</td><td>状态可见</td></tr><tr><td>5</td><td>查看逐项结果</td><td>3 成功、1 已有、1 超时</td><td>理解部分结果</td></tr><tr><td>6</td><td>选择“重试失败项”</td><td>仅重试 timeout</td><td>无重复副作用</td></tr><tr><td>7</td><td>返回成员页</td><td>待接受与已有成员可见</td><td>完成确认</td></tr></tbody></table><p>其中 3 个成功包含 li、wang 和修正后的 bad。成功标准最初写“2 个新邀请”不再符合修正后输入，观察前发现定义错误，应修正为 3 个，而不能在结果出来后选择有利解释。</p><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>已邀请：3</span></span>
<span class="line"><span>已是成员：1</span></span>
<span class="line"><span>暂时失败后重试成功：1</span></span>
<span class="line"><span>重复邀请：0</span></span>
<span class="line"><span>非计划帮助：0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>第二次观察中，参与者选择“重新提交全部”而不是“只重试失败项”。原型必须让服务端模拟层返回相同邀请 ID，避免重复；同时记录两个操作名称可能难区分。若原型没有幂等模拟，不能据此宣称方案安全。</p><p>第三次观察只用键盘，标签删除按钮名称均为“删除”，无法确定对象。这是可访问性与内容问题，需要修正为“删除 <a href="mailto:li@example.com" target="_blank" rel="noreferrer">li@example.com</a>”，并用屏幕阅读器复测。</p><h3 id="验证结论" tabindex="-1">验证结论 <a class="header-anchor" href="#验证结论" aria-label="Permalink to &quot;验证结论&quot;">​</a></h3><ul><li>逐项结果支持修正与重试假设，但需要保持成功项不可重复。</li><li>“重试失败项”和“重新提交全部”应避免同时作为相似主要操作。</li><li>原型不能证明邮件送达、服务端授权和生产延迟；这些进入工程验证。</li></ul><h2 id="观察记录模板" tabindex="-1">观察记录模板 <a class="header-anchor" href="#观察记录模板" aria-label="Permalink to &quot;观察记录模板&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 假设：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原型范围与限制：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 任务/输入/完成标准：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 参与者或检查角色：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 环境：</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 时间/步骤 | 动作 | 预测/判断 | 原型响应 | 编码 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- | --- | --- |</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 结果：成功/错误成功/部分/失败/未知</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 帮助：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 严重错误与恢复：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原型故障：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 证据支持/反证：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 下一版改动与复测：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>任务提示泄露路径：只给目标、数据和完成状态。</li><li>完成标准在观察后修改：观察前冻结，发现定义错误要透明记录。</li><li>把“到达最后一屏”算成功：检查对象和业务结果。</li><li>主持人立即帮助或赞同：记录帮助并使用中性提示。</li><li>把原型未实现当产品问题，或把假数据顺滑当生产证明。</li><li>只观察成功路径：准备错误、权限、等待和恢复。</li><li>用少量观察计算总体百分比。</li><li>修正画面后换任务，无法比较前后。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>写待验证假设、原型能力与不可推断范围。</li><li>设计不泄露路径的任务、固定输入和完成类别。</li><li>实现主路径、关键状态与可重复失败。</li><li>准备中性说明和非计划帮助记录规则。</li><li>观察动作、判断、原型响应、错误和恢复。</li><li>验证实际对象结果，不只看最终画面。</li><li>分离设计问题、原型故障和工程未知。</li><li>修改后使用相同任务、输入与口径复测。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>验证“取消订阅”原型。</p><p>完成时应满足：</p><ul><li>任务不包含设置、按钮或页面名称；</li><li>明确立即取消、周期末取消、退款和数据保留规则；</li><li>原型覆盖等待、失败、结果未知和撤销/恢复；</li><li>成功标准含订阅权威状态和重新进入后的结果；</li><li>记录帮助、错误成功和原型限制；</li><li>仅用键盘完成一次，并检查焦点与状态消息；</li><li>迭代前后使用相同任务和数据复测。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/design/making-prototypes" target="_blank" rel="noreferrer">GOV.UK Service Manual：Making prototypes</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/usability-benchmarking-a-website-or-whole-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Usability benchmarking a website or whole service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-the-success-of-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring the success of your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/test-evaluate/" target="_blank" rel="noreferrer">W3C WAI：Evaluating Web Accessibility Overview</a>（访问日期：2026-07-17）</li></ul>`,73)])])}const u=s(l,[["render",t]]);export{b as __pageData,u as default};
